// AgilityServ Website Signal Engine — All-in-One Node
const body = $input.first().json.body || $input.first().json;
const ticker = (body.ticker || '').toUpperCase().trim();
if (!ticker) throw new Error('INVALID_TICKER');

const API_KEY = 'REDACTED_XAI_API_KEY';

const p = {
  ticker,
  price: parseFloat(body.price) || 0,
  changePct: parseFloat(body.changePct) || 0,
  rsi: parseFloat(body.rsi) || 50,
  macd: parseFloat(body.macd) || 0,
  macdSignal: parseFloat(body.macdSignal) || 0,
  macdHist: parseFloat(body.macdHist) || 0,
  ema20: parseFloat(body.ema20) || 0,
  ema50: parseFloat(body.ema50) || 0,
  bbUpper: parseFloat(body.bbUpper) || 0,
  bbMiddle: parseFloat(body.bbMiddle) || 0,
  bbLower: parseFloat(body.bbLower) || 0,
  bbPosition: parseFloat(body.bbPosition) || 0.5,
  atr: parseFloat(body.atr) || 0,
  obvTrend: body.obvTrend || 'NEUTRAL',
  volRatio: parseFloat(body.volRatio) || 1,
  high52: parseFloat(body.high52) || 0,
  low52: parseFloat(body.low52) || 0,
  lastDate: body.lastDate || 'N/A',
  roc10: parseFloat(body.roc10) || 0
};
p.emaCross = p.ema20 > p.ema50 ? 'BULLISH' : 'BEARISH';
p.distH = p.high52 > 0 ? (((p.price - p.high52) / p.high52) * 100).toFixed(1) : 'N/A';
p.distL = p.low52 > 0 ? (((p.price - p.low52) / p.low52) * 100).toFixed(1) : 'N/A';

const userMsg = "Analyze " + p.ticker + " (data: " + p.lastDate + ")\n" +
  "PRICE: $" + p.price + " | Change: " + p.changePct + "% | ROC-10d: " + p.roc10 + "%\n" +
  "TREND: EMA20=$" + p.ema20 + " EMA50=$" + p.ema50 + " Cross=" + p.emaCross + "\n" +
  "MACD: " + p.macd + " Signal=" + p.macdSignal + " Hist=" + p.macdHist + "\n" +
  "MOMENTUM: RSI=" + p.rsi + "\n" +
  "VOLATILITY: BB Upper=$" + p.bbUpper + " Mid=$" + p.bbMiddle + " Lower=$" + p.bbLower + " Pos=" + p.bbPosition + " ATR=$" + p.atr + "\n" +
  "VOLUME: OBV=" + p.obvTrend + " VolRatio=" + p.volRatio + "x\n" +
  "RANGE: 52W High=$" + p.high52 + " (" + p.distH + "% from high) Low=$" + p.low52 + " (+" + p.distL + "% from low)\n\n" +
  'Return ONLY valid JSON (no markdown):\n{"signal":"BUY" or "SELL" or "STAND ASIDE","confidence":0-100,"correlationScore":0-100,"vcGateScore":0-100,"reasons":["reason with data","reason","reason","reason"],"tradePlan":{"direction":"LONG" or "SHORT","entry":"$X","stopLoss":"$X","target1":"$X","target2":"$X","riskReward":"1:X"},"standAsideConditions":["if STAND ASIDE"],"marketContext":"1 sentence"}';

let grokRaw;
try {
  const gResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.x.ai/v1/chat/completions',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + API_KEY
    },
    body: JSON.stringify({
      model: 'grok-3',
      temperature: 0.2,
      max_tokens: 900,
      messages: [
        { role: 'system', content: 'You are the VC Gate Decision Engine for the AgilityServ Quantum Trading Pipeline. Output ONLY valid JSON — no markdown, no explanation outside JSON.' },
        { role: 'user', content: userMsg }
      ]
    })
  });
  grokRaw = (gResp.choices && gResp.choices[0] && gResp.choices[0].message && gResp.choices[0].message.content) || '';
} catch (err) {
  grokRaw = '';
}

let parsed;
try {
  const cleaned = grokRaw.replace(/```json\n?|\n?```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = {
    signal: 'STAND ASIDE', confidence: 50, correlationScore: 50, vcGateScore: 50,
    reasons: ['Analysis inconclusive at current levels.','Wait for EMA cross confirmation.','RSI neutral — no extreme to trade from.','Volume not confirming directional move.'],
    tradePlan: null, standAsideConditions: ['Wait for EMA20/EMA50 cross confirmation.'],
    marketContext: 'Mixed signals — no clear edge identified.'
  };
}
const colorMap = {
  'BUY': { color: '#00E599', glow: 'rgba(0,229,153,0.35)' },
  'SELL': { color: '#FF4D4D', glow: 'rgba(255,77,77,0.35)' },
  'STAND ASIDE': { color: '#FFB547', glow: 'rgba(255,181,71,0.35)' }
};
parsed.meta = colorMap[parsed.signal] || colorMap['STAND ASIDE'];
parsed.poweredBy = 'Grok-3 \u00b7 AgilityServ Quantum Pipeline';

// Pass JSON as string in responseBody field
return [{ json: { responseBody: JSON.stringify(parsed) } }];
